// ═══════════════════════════════════════
// EXTRACCIÓN DE CAMPOS DESDE MARKDOWN
// ═══════════════════════════════════════
// LlamaCloud nos devolvió el PDF como markdown.
// Acá extraemos los campos con regex simples para armar
// el mismo shape que viene por el webhook JSON.
// Didácticamente: en producción usaríamos un LLM de extracción
// o un esquema más robusto (p.ej. LlamaExtract).

const incoming = $input.first().json;
const markdown = incoming?.markdown || incoming?.result || '';
const pdfInput = $('📄 Webhook PDF').first().json.body || $('📄 Webhook PDF').first().json;

if (!markdown) {
  return [{
    json: {
      patientId: pdfInput.patientId || 'unknown',
      symptoms: null,
      parseError: 'No se pudo obtener markdown de LlamaCloud',
      source: 'pdf-llamacloud-failed'
    }
  }];
}

function extractField(md, labels) {
  for (const label of labels) {
    const re = new RegExp(`\\*?\\*?${label}\\*?\\*?\\s*[:\\-]\\s*([^\\n|]+)`, 'i');
    const m = md.match(re);
    if (m) return m[1].trim().replace(/\*+/g, '').replace(/\|.*$/, '').trim();
  }
  return null;
}

function extractNumber(text) {
  if (!text) return null;
  const m = String(text).match(/(\d+(?:[.,]\d+)?)/);
  return m ? Number(m[1].replace(',', '.')) : null;
}

const age = extractNumber(extractField(markdown, ['edad', 'age']));
const symptoms = extractField(markdown, ['síntomas', 'sintomas', 'symptoms', 'motivo de consulta', 'motivo']);
const bp = extractField(markdown, ['presión arterial', 'presion arterial', 'ta', 'tension arterial', 'blood pressure']);
const hr = extractNumber(extractField(markdown, ['frecuencia cardíaca', 'frecuencia cardiaca', 'fc', 'heart rate', 'hr']));
const spo2 = extractNumber(extractField(markdown, ['saturación', 'saturacion', 'spo2', 'sat o2']));
const temp = extractNumber(extractField(markdown, ['temperatura', 'temp']));

const vitals = {};
if (bp) vitals.bp = bp;
if (hr != null) vitals.hr = hr;
if (spo2 != null) vitals.spo2 = spo2;
if (temp != null) vitals.temp = temp;

return [{
  json: {
    patientId: pdfInput.patientId || 'pdf-' + Date.now(),
    age,
    symptoms: symptoms || 'Ver informe adjunto (no se pudo extraer síntomas explícitos)',
    vitals,
    _pdfMarkdownPreview: markdown.slice(0, 400),
    source: 'pdf-llamacloud'
  }
}];

// ═══════════════════════════════════════
// VALIDACIÓN + ANONIMIZACIÓN + INICIO DE TRACKING
// ═══════════════════════════════════════

const input = $input.first().json.body || $input.first().json;

const required = ['patientId', 'symptoms'];
const missing = required.filter(f => !input[f]);

if (missing.length > 0) {
  return [{
    json: {
      valid: false,
      error: `Campos faltantes: ${missing.join(', ')}`,
      statusCode: 400
    }
  }];
}

const hashId = (id) => {
  let h = 0;
  for (let i = 0; i < String(id).length; i++) {
    h = ((h << 5) - h) + String(id).charCodeAt(i);
  }
  return 'hash_' + Math.abs(h).toString(36);
};

const vitals = input.vitals || {};
const bpSystolic = vitals.bp ? parseInt(String(vitals.bp).split('/')[0]) : null;

const hasCriticalVitals = (
  (vitals.spo2 != null && vitals.spo2 < 92) ||
  (vitals.hr != null && (vitals.hr > 110 || vitals.hr < 50)) ||
  (bpSystolic != null && bpSystolic > 170) ||
  (vitals.temp != null && vitals.temp >= 39)
);

return [{
  json: {
    valid: true,
    patientHash: hashId(input.patientId),
    age: input.age || null,
    symptoms: String(input.symptoms).trim(),
    vitals,
    hasCriticalVitals,
    timestamp: new Date().toISOString(),
    startedAtMs: Date.now(),
    inputSource: input.source || 'webhook-json'
  }
}];

// ═══════════════════════════════════════
// BÚSQUEDA SEMÁNTICA (SIMULADA)
// ═══════════════════════════════════════

const input = $input.first().json;

const clinicalDocs = [
  {
    id: 'doc-001',
    title: 'Protocolo Síndrome Coronario Agudo',
    content: 'El dolor toracico opresivo irradiado a brazo izquierdo con disnea sugiere infarto agudo de miocardio. Actuar en ventana dorada menor a 90 minutos. Solicitar ECG, troponinas, activar hemodinamia.',
    specialty: 'cardiologia',
    urgency: 'critica'
  },
  {
    id: 'doc-002',
    title: 'Manejo de Crisis Hipertensiva',
    content: 'Presion arterial mayor a 180/120 con sintomas como cefalea intensa, vision borrosa o dolor toracico indica emergencia hipertensiva. Descenso controlado de PA 20 por ciento primera hora.',
    specialty: 'cardiologia',
    urgency: 'alta'
  },
  {
    id: 'doc-003',
    title: 'Evaluación de Disnea Aguda',
    content: 'Dificultad respiratoria con saturacion menor a 92 por ciento requiere oxigenoterapia inmediata. Diagnosticos diferenciales TEP, neumonia, insuficiencia cardiaca, broncoespasmo.',
    specialty: 'neumologia',
    urgency: 'alta'
  },
  {
    id: 'doc-004',
    title: 'Protocolo Sepsis Temprana',
    content: 'Fiebre con taquicardia e hipotension en contexto de infeccion. Aplicar qSOFA. Bundle de sepsis cultivos, lactato, antibioticos en primera hora, fluidos cristaloides.',
    specialty: 'infectologia',
    urgency: 'critica'
  },
  {
    id: 'doc-005',
    title: 'Cefalea de Alarma - Red Flags',
    content: 'Cefalea subita intensa thunderclap, focalidad neurologica, fiebre, trauma craneal reciente o mayor a 50 años. Descartar HSA, meningitis, tumor. TC de cerebro urgente.',
    specialty: 'neurologia',
    urgency: 'alta'
  },
  {
    id: 'doc-006',
    title: 'Consulta General - Baja Complejidad',
    content: 'Sintomas leves sin signos de alarma. Evaluacion ambulatoria estandar, seguimiento por medico de cabecera. Educar sobre signos de empeoramiento.',
    specialty: 'clinica',
    urgency: 'baja'
  }
];

function embed(text) {
  const vec = new Array(128).fill(0);
  const words = String(text).toLowerCase()
    .replace(/[^a-záéíóúñ ]/g, ' ')
    .split(/\s+/)
    .filter(w => w.length > 2);
  words.forEach(w => {
    for (let i = 0; i < w.length; i++) {
      vec[(w.charCodeAt(i) * 31 + i) % 128] += 1;
    }
  });
  const mag = Math.sqrt(vec.reduce((s, v) => s + v * v, 0));
  return mag > 0 ? vec.map(v => v / mag) : vec;
}

function cosineSim(a, b) {
  return a.reduce((s, v, i) => s + v * b[i], 0);
}

const queryVec = embed(input.symptoms);

const ranked = clinicalDocs
  .map(doc => ({
    ...doc,
    similarity: +cosineSim(queryVec, embed(doc.content + ' ' + doc.title)).toFixed(4)
  }))
  .sort((a, b) => b.similarity - a.similarity)
  .slice(0, 3);

return [{
  json: {
    ...input,
    relevantDocs: ranked,
    topDocContext: ranked.map(d => `[${d.title}]: ${d.content}`).join('\n\n')
  }
}];

// ═══════════════════════════════════════
// PARSER ROBUSTO DE RESPUESTA IA
// ═══════════════════════════════════════
// Maneja: JSON directo, markdown code fences, texto extra.
// La validación de schema se hace en el siguiente nodo.

const aiData = $input.first().json;
const previousData = $('🔍 Búsqueda Semántica').first().json;

function extractJson(text) {
  if (text == null) return null;
  if (typeof text === 'object') return text;
  if (typeof text !== 'string') return null;
  try { return JSON.parse(text); } catch (e) {}
  const cleaned = text
    .replace(/^```(?:json)?\s*/i, '')
    .replace(/\s*```\s*$/, '')
    .trim();
  try { return JSON.parse(cleaned); } catch (e) {}
  const match = text.match(/\{[\s\S]*\}/);
  if (match) {
    try { return JSON.parse(match[0]); } catch (e) {}
  }
  return null;
}

const content = aiData?.choices?.[0]?.message?.content;
const parsed = extractJson(content);

return [{
  json: {
    ...previousData,
    aiAnalysis: parsed,
    parseSucceeded: parsed != null,
    source: 'openrouter-gemini-2.0-flash',
    tokensUsed: aiData?.usage?.total_tokens || 0,
    rawContent: content
  }
}];

// ═══════════════════════════════════════
// VALIDACIÓN DE OUTPUT SCHEMA
// ═══════════════════════════════════════
// JSON Schema manual. Si falla, marca schemaValid=false
// y el IF siguiente lo rutea al fallback.

const d = $input.first().json;
const a = d.aiAnalysis;

const errors = [];

if (!d.parseSucceeded || !a || typeof a !== 'object') {
  errors.push('aiAnalysis no es un objeto JSON válido');
}

if (a) {
  if (typeof a.analysis !== 'string' || a.analysis.trim().length === 0) {
    errors.push('analysis debe ser string no vacío');
  }
  const validUrgency = ['critica', 'alta', 'media', 'baja'];
  const urgencyNormalized = String(a.urgency || '').toLowerCase()
    .replace('crítica', 'critica').replace('critical', 'critica')
    .replace('high', 'alta').replace('medium', 'media').replace('moderada', 'media')
    .replace('low', 'baja');
  if (!validUrgency.includes(urgencyNormalized)) {
    errors.push(`urgency debe ser uno de: ${validUrgency.join(', ')} (recibido: ${a.urgency})`);
  }
  if (typeof a.recommendedAction !== 'string' || a.recommendedAction.trim().length === 0) {
    errors.push('recommendedAction debe ser string no vacío');
  }
  if (!Array.isArray(a.differentialDiagnosis)) {
    errors.push('differentialDiagnosis debe ser array');
  } else if (!a.differentialDiagnosis.every(x => typeof x === 'string')) {
    errors.push('differentialDiagnosis debe ser array de strings');
  }
  a.urgency = urgencyNormalized;
}

const schemaValid = errors.length === 0;

return [{
  json: {
    ...d,
    schemaValid,
    schemaErrors: errors
  }
}];

// ═══════════════════════════════════════
// NORMALIZADOR POST-SCHEMA (happy path)
// ═══════════════════════════════════════
// El schema validó OK. Armamos el shape final que consume
// la Clasificación de Riesgo.

const d = $input.first().json;

return [{
  json: {
    patientHash: d.patientHash,
    age: d.age,
    symptoms: d.symptoms,
    vitals: d.vitals,
    hasCriticalVitals: d.hasCriticalVitals,
    relevantDocs: d.relevantDocs,
    startedAtMs: d.startedAtMs,
    inputSource: d.inputSource,
    aiAnalysis: {
      analysis: d.aiAnalysis.analysis,
      urgency: d.aiAnalysis.urgency,
      recommendedAction: d.aiAnalysis.recommendedAction,
      differentialDiagnosis: d.aiAnalysis.differentialDiagnosis
    },
    source: d.source,
    fallbackUsed: false,
    schemaValid: true,
    schemaErrors: [],
    tokensUsed: d.tokensUsed
  }
}];

// ═══════════════════════════════════════
// FALLBACK: ANÁLISIS BASADO EN REGLAS
// ═══════════════════════════════════════
// Se activa si:
//   (a) la IA no respondió,
//   (b) no se pudo parsear el JSON, o
//   (c) el JSON no cumple el schema.

const data = $('🔍 Búsqueda Semántica').first().json;

// Detección del motivo (best-effort, para logging)
let fallbackReason = 'ai-request-failed';
try {
  const maybeParsed = $('📝 Parsear Respuesta IA')?.first()?.json;
  if (maybeParsed) {
    if (!maybeParsed.parseSucceeded) fallbackReason = 'json-parse-failed';
    else fallbackReason = 'schema-invalid';
  }
} catch (e) { /* el nodo de parse no corrió */ }

let schemaErrors = [];
try {
  const maybeValidated = $('✅ Validar Output Schema')?.first()?.json;
  if (maybeValidated?.schemaErrors) schemaErrors = maybeValidated.schemaErrors;
} catch (e) {}

let urgency = 'media';
let recommendedAction = 'Evaluación médica presencial';

if (data.hasCriticalVitals) {
  urgency = 'critica';
  recommendedAction = '🚨 Activar protocolo de emergencia. Derivar a guardia inmediatamente.';
} else if (data.relevantDocs[0]?.urgency === 'critica') {
  urgency = 'alta';
  recommendedAction = `Evaluación urgente. Consultar protocolo: ${data.relevantDocs[0].title}`;
} else if (data.relevantDocs[0]?.urgency === 'alta') {
  urgency = 'alta';
  recommendedAction = 'Derivar a guardia dentro de las próximas 2 horas';
} else {
  urgency = 'baja';
  recommendedAction = 'Consulta programada con médico de cabecera';
}

return [{
  json: {
    patientHash: data.patientHash,
    age: data.age,
    symptoms: data.symptoms,
    vitals: data.vitals,
    hasCriticalVitals: data.hasCriticalVitals,
    relevantDocs: data.relevantDocs,
    startedAtMs: data.startedAtMs,
    inputSource: data.inputSource,
    aiAnalysis: {
      analysis: `FALLBACK (${fallbackReason}): top match con "${data.relevantDocs[0]?.title}" (similitud ${data.relevantDocs[0]?.similarity}).`,
      urgency,
      recommendedAction,
      differentialDiagnosis: data.relevantDocs.map(d => d.title)
    },
    source: 'fallback-rules-engine',
    fallbackUsed: true,
    fallbackReason,
    schemaValid: false,
    schemaErrors,
    tokensUsed: 0
  }
}];

// ═══════════════════════════════════════
// CLASIFICACIÓN FINAL + PRIORIZACIÓN
// ═══════════════════════════════════════

const d = $input.first().json;

const urgencyScore = { critica: 4, alta: 3, media: 2, baja: 1 };

let aiScore = urgencyScore[d.aiAnalysis.urgency] || 2;

if (d.hasCriticalVitals && aiScore < 3) aiScore = 3;

const priority =
  aiScore >= 4 ? 'P1_CRITICAL' :
  aiScore === 3 ? 'P2_HIGH' :
  aiScore === 2 ? 'P3_MEDIUM' : 'P4_LOW';

const slaMinutes =
  priority === 'P1_CRITICAL' ? 5 :
  priority === 'P2_HIGH' ? 30 :
  priority === 'P3_MEDIUM' ? 120 : 1440;

return [{
  json: {
    ...d,
    triage: {
      priority,
      urgency: d.aiAnalysis.urgency,
      slaMinutes,
      slaDeadline: new Date(Date.now() + slaMinutes * 60000).toISOString(),
      overrideApplied: d.hasCriticalVitals && urgencyScore[d.aiAnalysis.urgency] < 3
    }
  }
}];

// ═══════════════════════════════════════
// LOG ESTRUCTURADO + MÉTRICAS
// ═══════════════════════════════════════
// Genera una línea de log JSON por ejecución.
// En prod iría a un sink (Loki, Datadog, CloudWatch).
// Acá la imprimimos al stdout del contenedor y la
// propagamos para que el nodo de alerta la use.

const d = $input.first().json;
const now = Date.now();
const latencyMs = d.startedAtMs ? (now - d.startedAtMs) : null;

const logEntry = {
  event: 'triage_completed',
  ts: new Date(now).toISOString(),
  patientHash: d.patientHash,
  priority: d.triage.priority,
  urgency: d.triage.urgency,
  slaMinutes: d.triage.slaMinutes,
  latencyMs,
  tokensUsed: d.tokensUsed,
  fallbackUsed: d.fallbackUsed === true,
  fallbackReason: d.fallbackReason || null,
  schemaValid: d.schemaValid !== false,
  schemaErrors: d.schemaErrors || [],
  overrideApplied: d.triage.overrideApplied === true,
  inputSource: d.inputSource || 'webhook-json',
  source: d.source
};

// Imprimir al stdout — aparece en `docker logs n8n-dev-c2`
console.log('[TRIAGE_LOG] ' + JSON.stringify(logEntry));

// Criterios de alerta
const shouldAlert = (
  logEntry.fallbackUsed === true ||
  (latencyMs != null && latencyMs > 8000) ||
  logEntry.overrideApplied === true
);

return [{
  json: {
    ...d,
    log: logEntry,
    shouldAlert
  }
}];

parameters.jsonBody:
={{ JSON.stringify({
  alert: true,
  reasons: [
    $json.fallbackUsed ? ('fallback:' + ($json.fallbackReason || 'unknown')) : null,
    ($json.log.latencyMs != null && $json.log.latencyMs > 8000) ? ('latency_high:' + $json.log.latencyMs + 'ms') : null,
    $json.triage.overrideApplied ? 'override_applied' : null
  ].filter(Boolean),
  log: $json.log,
  patientHash: $json.patientHash
}) }}
